// Apply simple damage
UGameplayStatics::ApplyDamage(
    TargetActor,
    50.f,                          // Damage amount
    GetController(),                // Instigator (who shot)
    this,                          // DamageCauser (the weapon/projectile)
    UDamageType::StaticClass()     // Damage type
);

// Apply point damage (with direction)
UGameplayStatics::ApplyPointDamage(
    HitResult.GetActor(), 50.f, ShotDirection, HitResult,
    GetController(), this, UFireDamageType::StaticClass()
);

// Apply radial damage (explosion)
UGameplayStatics::ApplyRadialDamageWithFalloff(
    GetWorld(), 100.f, 10.f,       // BaseDamage, MinDamage
    GetActorLocation(), 200.f, 500.f, // Origin, InnerRadius, OuterRadius
    1.f,                           // Falloff exponent
    UDamageType::StaticClass(),
    TArray<AActor*>(),             // Ignore actors
    this, GetController()          // Causer, Instigator
);

// Receiving damage — delegate approach
void AMyCharacter::BeginPlay() {
    OnTakeAnyDamage.AddDynamic(this, &AMyCharacter::HandleDamage);
}

void AMyCharacter::HandleDamage(AActor* DamagedActor, float Damage,
    const UDamageType* DamageType, AController* Instigator, AActor* DamageCauser) {
    Health -= Damage;
    if (Health <= 0.f) Die(Instigator);
}

// Override approach
float AMyCharacter::TakeDamage(float Damage, FDamageEvent const& DamageEvent,
    AController* Instigator, AActor* DamageCauser) {
    float ActualDamage = Super::TakeDamage(Damage, DamageEvent, Instigator, DamageCauser);
    Health -= ActualDamage;
    return ActualDamage;
}
